import { createTool } from '@mastra/core/tools';
import { Agent } from '@mastra/core/agent';
import { z } from 'zod';
import * as fs from 'fs';
import * as path from 'path';

const calculatorTool = createTool({
  id: 'calculator',
  description: 'A simple calculator tool to perform basic arithmetic operations.',
  inputSchema: z.object({
    a: z.number(),
    b: z.number(),
    operation: z.enum(['add', 'subtract', 'multiply', 'divide']),
  }),
  execute: async ({ input }) => {
    const { a, b, operation } = input;
    let result: number;
    switch (operation) {
      case 'add':
        result = a + b;
        break;
      case 'subtract':
        result = a - b;
        break;
      case 'multiply':
        result = a * b;
        break;
      case 'divide':
        result = a / b;
        break;
      default:
        throw new Error('Invalid operation');
    }
    return { result };
  },
});

const agent = new Agent({
  id: 'calculator-agent',
  name: 'Calculator Agent',
  instructions: 'You are a helpful assistant that can perform calculations using the calculator tool.',
  model: 'openai/gpt-4o-mini',
  tools: {
    calculator: calculatorTool,
  },
});

async function main() {
  try {
    const response = await agent.generate('What is 15 multiplied by 7?');
    const outputText = response.text;

    const logPath = path.join(__dirname, 'output.log');
    fs.writeFileSync(logPath, outputText);
    console.log('Output written to output.log');
  } catch (error) {
    console.error('Error:', error);
  }
}

main();

